// EmergencyRedemption is the network-wide stepped-redemption brake (governance-activated): during a
// run, each holder's cumulative redemption per institution is capped, and the cap relaxes over time
// until full settlement. The caps are network governance parameters; the defaults are: before day 30
// → halted; from day 30 → 200 PHI (20,000,000 Toman); from day 60 → 2,000 PHI (200,000,000 Toman);
// from day 90 → unlimited.
type EmergencyRedemption struct {
	Active bool `protobuf:"varint,1,opt,name=active,proto3" json:"active,omitempty"`
	// unix seconds when the current emergency was activated (set by the keeper on activation).
	StartedAt int64 `protobuf:"varint,2,opt,name=started_at,json=startedAt,proto3" json:"started_at,omitempty"`
	// cumulative per-holder redeem cap (Toman) during [0,30) days ("" or "0" = redemptions halted).
	CapBeforeDay30 string `protobuf:"bytes,3,opt,name=cap_before_day30,json=capBeforeDay30,proto3" json:"cap_before_day30,omitempty"`
	// cumulative per-holder redeem cap (Toman) from day 30 (default 20,000,000).
	CapFromDay30 string `protobuf:"bytes,4,opt,name=cap_from_day30,json=capFromDay30,proto3" json:"cap_from_day30,omitempty"`
	// cumulative per-holder redeem cap (Toman) from day 60 (default 200,000,000).
	CapFromDay60 string `protobuf:"bytes,5,opt,name=cap_from_day60,json=capFromDay60,proto3" json:"cap_from_day60,omitempty"`
}

