// Params are the institutions module parameters; changed only via governance.
type Params struct {
	// operator/company address — allowed to Register/Remove/Freeze
	Operator string `protobuf:"bytes,1,opt,name=operator,proto3" json:"operator,omitempty"`
	// fixed rate: 1 PHI = phi_to_toman Toman (canonical = 100,000)
	PhiToToman uint64 `protobuf:"varint,2,opt,name=phi_to_toman,json=phiToToman,proto3" json:"phi_to_toman,omitempty"`
	// protocol floor for the per-transaction redeem cap (Toman; "" or "0" = no floor).
	// An institution cannot set its redeem cap below this floor (user protection — §13.4).
	RedeemFloorPerTx string `protobuf:"bytes,3,opt,name=redeem_floor_per_tx,json=redeemFloorPerTx,proto3" json:"redeem_floor_per_tx,omitempty"`
	// network-wide emergency stepped-redemption brake (governance-activated; default inactive).
	EmergencyRedemption EmergencyRedemption `protobuf:"bytes,4,opt,name=emergency_redemption,json=emergencyRedemption,proto3" json:"emergency_redemption"`
	// destination for penalty coins (slashed stake, governance deposit "burns") that are redirected
	// here instead of being burned, so total uphi supply — and therefore solvency — stays constant.
	// Empty ("") resolves to the operator account, then to the governance authority account.
	PenaltyDestination string `protobuf:"bytes,5,opt,name=penalty_destination,json=penaltyDestination,proto3" json:"penalty_destination,omitempty"`
	// a mint at or above this Toman amount must collect the institution's aggregated ADMIN multisig
	// approvals before it executes ("" or "0" = no large-mint multisig). Defends against a single
	// operator/admin key minting an unbounded amount.
	LargeMintThresholdToman string `protobuf:"bytes,6,opt,name=large_mint_threshold_toman,json=largeMintThresholdToman,proto3" json:"large_mint_threshold_toman,omitempty"`
	// protocol hard ceiling on a single mint (Toman; "" or "0" = no ceiling). Every mint must be at or
	// below this, regardless of an institution's own (possibly unset) caps — bounds inflation.
	MintCeilingPerTx string `protobuf:"bytes,7,opt,name=mint_ceiling_per_tx,json=mintCeilingPerTx,proto3" json:"mint_ceiling_per_tx,omitempty"`
	// protocol hard ceiling on an institution's cumulative daily mint (Toman; "" or "0" = no ceiling).
	MintCeilingDaily string `protobuf:"bytes,8,opt,name=mint_ceiling_daily,json=mintCeilingDaily,proto3" json:"mint_ceiling_daily,omitempty"`
}

